CREATE TABLE `business` (
  `business_id` binary(16) NOT NULL,
  `business_name` varchar(150) NOT NULL,
  `street_address` varchar(150) DEFAULT NULL,
  `county` varchar(50) DEFAULT NULL,
  `city` varchar(50) DEFAULT NULL,
  `state_code` char(2) NOT NULL DEFAULT 'TX',
  `zip_code` varchar(10) DEFAULT NULL,
  `territory_id` int DEFAULT NULL,
  `phone_number` varchar(20) DEFAULT NULL,
  `email` varchar(100) DEFAULT NULL,
  `created_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` datetime DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  PRIMARY KEY (`business_id`),
  KEY `idx_business_territory_id` (`territory_id`),
  KEY `idx_business_zip_code` (`zip_code`),
  CONSTRAINT `fk_business_territory` FOREIGN KEY (`territory_id`) REFERENCES `territory` (`territory_id`) ON DELETE SET NULL ON UPDATE RESTRICT,
  CONSTRAINT `chk_business_state_code` CHECK ((char_length(`state_code`) = 2)),
  CONSTRAINT `chk_business_zip_code` CHECK (((`zip_code` is null) or (char_length(`zip_code`) in (5,10))))
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;
